import React from 'react';
import { Link } from 'react-router-dom';
import { FaCalendarAlt, FaBuilding, FaArrowRight } from 'react-icons/fa';
import formatDate from '../utils/formatDate';

const SchemeCard = ({ scheme }) => {
  const { _id, name, department, description, lastDate } = scheme;

  // Truncate description if it's too long
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 transition-all duration-200 hover:shadow-lg border border-gray-200">
      <Link to={`/schemes/${_id}`}>
        <h3 className="text-xl font-semibold text-green-700 mb-2 hover:text-green-800">{name}</h3>
      </Link>
      
      <div className="flex items-center text-sm text-gray-500 mb-3">
        <div className="flex items-center mr-4">
          <FaBuilding className="mr-1 text-blue-600" />
          <span>{department}</span>
        </div>
        {lastDate && (
          <div className="flex items-center">
            <FaCalendarAlt className="mr-1 text-red-600" />
            <span>Last Date: {formatDate(lastDate)}</span>
          </div>
        )}
      </div>
      
      <p className="text-gray-700 mb-4">{truncateText(description)}</p>
      
      <div className="flex justify-end">
        <Link 
          to={`/schemes/${_id}`} 
          className="flex items-center px-3 py-1 bg-green-600 text-white rounded hover:bg-green-700 transition-colors"
        >
          View Details <FaArrowRight className="ml-1" />
        </Link>
      </div>
    </div>
  );
};

export default SchemeCard;
